// Transform flat Google Sheet rows into nested format for Flask
// Columns: name | student_email | parent_email | subject | exam_type (sessional/semester) | term | score | max_score

const rows = items.map(i => i.json);
const studentsMap = {};

for (const row of rows) {
  const name = (row['name'] || row['Name'] || '').trim();
  if (!name) continue;

  if (!studentsMap[name]) {
    studentsMap[name] = {
      name,
      student_email: (row['student_email'] || row['Student Email'] || '').trim(),
      parent_email:  (row['parent_email']  || row['Parent Email']  || '').trim(),
      marks: []
    };
  }

  const subject   = (row['subject']   || row['Subject']   || '').trim();
  const exam_type = (row['exam_type'] || row['Exam Type'] || '').trim().toLowerCase();
  const term      = parseInt(row['term'] || row['Term'] || 1, 10) || 1;
  const score     = parseFloat(row['score']     || row['Score']     || 0) || 0;
  const max_score = parseFloat(row['max_score'] || row['Max Score'] || 100) || 100;

  if (subject && (exam_type === 'sessional' || exam_type === 'semester')) {
    studentsMap[name].marks.push({ subject, exam_type, term, score, max_score });
  }
}

return [{ json: { students: Object.values(studentsMap) } }];
